--
-- Table structure for table `setting_definitions`
--

CREATE TABLE `setting_definitions` (
  `id` int UNSIGNED NOT NULL COMMENT 'PK. Referenced by setting_values to bind a stored value to its definition.',
  `key` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Unique machine-readable identifier used by the API and frontend to look up a setting, e.g. "msg.font_size". Never shown to the user.',
  `label` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Setting name, normally above field.',
  `description` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Human-readable explanation rendered directly on the settings screen, normally below field. Adding a new row here is sufficient to surface a new setting in the UI without any frontend code change.',
  `group` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Logical grouping used to cluster related settings under a shared header on the settings screen, e.g. "messaging", "system", "appearance".',
  `data_type` enum('string','integer','float','boolean','color','enum') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Tells the frontend which control to render (text input, number slider, color picker, toggle, dropdown). The value in setting_values is always TEXT and cast to this type at read time.',
  `options` json DEFAULT NULL COMMENT 'JSON array of objects with "label" and "value" keys, populated only when data_type = "enum" or "color", e.g. [{"label":"Light","value":"#ffffff"}]. NULL for all other types.',
  `default_value` text COLLATE utf8mb4_unicode_ci COMMENT 'Fallback value returned when no row exists in setting_values for the requested (setting_id, user_id) pair. Acts as tier-3 in the resolution chain: user value → global value → this.',
  `min_value` decimal(20,6) DEFAULT NULL COMMENT 'Lower bound for numeric types (integer, float). Enforced at the API layer before writing to setting_values. NULL means unbounded.',
  `max_value` decimal(20,6) DEFAULT NULL COMMENT 'Upper bound for numeric types (integer, float). Enforced at the API layer before writing to setting_values. NULL means unbounded.',
  `regex` text COLLATE utf8mb4_unicode_ci COMMENT 'Validation pattern applied to string-type settings before persisting. NULL means no pattern restriction.',
  `scope` enum('global','user') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '"global" means one shared value (user_id = NULL in setting_values) read by everyone. "user" means each user can carry their own row.',
  `is_overridable` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Only meaningful when scope = "global". When 1, a user may insert their own row in setting_values to override the global value.',
  `editable_by_roles` json DEFAULT NULL COMMENT 'JSON array of role IDs permitted to write this setting. NULL means no role restriction on writes.',
  `visible_to_roles` json DEFAULT NULL COMMENT 'JSON array of role IDs permitted to read this setting. NULL means the setting is visible to all authenticated users.'
) ;

